@@ -1973,0 +1973,46 @@
+// Check if the MachSpillCopyNode can use `movprfx` for fusion optimization.
+// (see https://documentation-service.arm.com/static/668bc0a369e89f01e39c4668?token=)
+// For example:
+//   movprfx z16.b, z18.b
+//   add z16.b, p0/m, z16.b, z17.b
+// will be fused as if one instruction:
+//   add z16.b, p0/m, z18.b, z17.b
+// and the execution of the instruction pair will be accelerated.
+static bool use_movprfx_for_spill_copy(const MachSpillCopyNode* copy_node,
+                                       OptoReg::Name dst_reg, PhaseRegAlloc* ra_) {
+  // Conservatively require that MachSpillCopyNode has only one use.
+  if (copy_node->outcnt() != 1) {
+    return false;
+  }
+
+  Node* use = copy_node->unique_out();
+  if (!use->is_Mach()) {
+    return false;
+  }
+  MachNode* mach_use = use->as_Mach();
+  OptoReg::Name use_dst_lo = ra_->get_reg_first(mach_use);
+  if (rc_class(use_dst_lo) != rc_float) {
+    return false;
+  }
+
+  // Need at least one data input, the first operand is destination
+  uint num_opnds = mach_use->num_opnds();
+  if (num_opnds < 2) {
+    return false;
+  }
+
+  // Get the first source register (input 1, as input 0 is usually control/memory),
+  // the MachSpillCopyNode must be the first source.
+  Node* first_input = mach_use->in(1);
+  if (first_input != copy_node) {
+    return false;
+  }
+
+  // Check if destination register of the use node equals the copy node's
+  // destination. This means the use node has the pattern: dst = op(dst, ...)
+  if (use_dst_lo != dst_reg) {
+    return false;
+  }
+  return true;
+}
